#include <iostream>
#include <string>
using namespace std;

class Animal {
protected:
    string name;

public:
    Animal(string name) : name(name) {
        cout << name << " (animal) created" << endl;
    }

    void eat() {
        cout << name << " is eating." << endl;
    }
};

class Dog : public Animal {
public:
    Dog(string name) : Animal(name) {
        cout << name << " (dog) created" << endl;
    }

    void bark() {
        cout << name << " says: Woof!" << endl;
    }
};

int main() {
    Dog d("Rex");
    d.eat();   // inherited from Animal
    d.bark();  // Dog's own method
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Animal {
public:
    string name;
    Animal(string n) : name(n) {}

    virtual void speak() {
        cout << name << ": ..." << endl;
    }
};

class Dog  : public Animal {
public:
    Dog(string n) : Animal(n) {}
    void speak() override { cout << name << ": Woof!"  << endl; }
};

class Cat  : public Animal {
public:
    Cat(string n) : Animal(n) {}
    void speak() override { cout << name << ": Meow!"  << endl; }
};

void makeSpeak(Animal& a) {  // takes base reference
    a.speak();               // calls the RIGHT version!
}

int main() {
    Dog d("Rex");
    Cat c("Whiskers");
    Animal a("Generic");

    makeSpeak(d);
    makeSpeak(c);
    makeSpeak(a);
    return 0;
}

#include <iostream>
#include <cmath>
using namespace std;

class Shape {
public:
    virtual double area()      = 0;  // pure virtual
    virtual double perimeter() = 0;  // pure virtual

    // Regular virtual with implementation:
    virtual void describe() {
        cout << typeid(*this).name() << ": area=" << area() << endl;
    }
};

class Circle : public Shape {
    double r;
public:
    Circle(double r) : r(r) {}
    double area()      override { return M_PI * r * r; }
    double perimeter() override { return 2 * M_PI * r; }
};

class Square : public Shape {
    double s;
public:
    Square(double s) : s(s) {}
    double area()      override { return s * s; }
    double perimeter() override { return 4 * s; }
};

int main() {
    // Shape s;  // compile error — abstract!
    Circle c(5);
    Square sq(4);

    cout << "Circle area: " << c.area() << endl;
    cout << "Square area: " << sq.area() << endl;

    return 0;
}

#include <iostream>
#include <string>
#include <memory>
using namespace std;

class Base {
public:
    virtual ~Base() { cout << "Base destroyed" << endl; }  // virtual!
    virtual void greet() { cout << "Hello from Base" << endl; }
};

class Derived : public Base {
    string data = "expensive resource";
public:
    ~Derived() { cout << "Derived destroyed (" << data << " freed)" << endl; }
    void greet() override { cout << "Hello from Derived" << endl; }
};

int main() {
    // Polymorphic deletion via base pointer:
    Base* p = new Derived();
    p->greet();
    delete p;  // calls Derived::~Derived() then Base::~Base() — correct!
    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class Animal {
public:
    string name;
    Animal(string n) : name(n) {}
    virtual ~Animal() = default;
    virtual void speak() = 0;
};

class Dog : public Animal {
public:
    Dog(string n) : Animal(n) {}
    void speak() override { cout << name << ": Woof" << endl; }
    void fetch() { cout << name << " fetches the ball!" << endl; }
};

class Cat : public Animal {
public:
    Cat(string n) : Animal(n) {}
    void speak() override { cout << name << ": Meow" << endl; }
    void purr() { cout << name << " purrs..." << endl; }
};

void interact(Animal* a) {
    a->speak();
    if (Dog* d = dynamic_cast<Dog*>(a)) {
        d->fetch();  // only for dogs
    } else if (Cat* c = dynamic_cast<Cat*>(a)) {
        c->purr();   // only for cats
    }
}

int main() {
    Animal* animals[] = {new Dog("Rex"), new Cat("Whiskers")};
    for (auto* a : animals) { interact(a); delete a; }
    return 0;
}
